import ts from"typescript";import{stripQuotes}from"../../ast-helpers.js";import{hasImportSpecifier}from"../helpers.js";import{scriptVisitor as visit}from"../index.js";export default visit(t=>t.statements.some(t=>hasImportSpecifier(t,"bun","$")),t=>{if(ts.isTaggedTemplateExpression(t)&&"$"===t.tag.getText())return stripQuotes(t.template.getText())});